import{_ as e,o as n,c as a,ak as t}from"./chunks/framework.DwHlt8HN.js";const u=JSON.parse('{"title":"Kubernetes（K8s）","description":"","frontmatter":{},"headers":[],"relativePath":"devops/k8s/index.md","filePath":"devops/k8s/index.md","lastUpdated":1774320699000}'),p={name:"devops/k8s/index.md"};function l(r,s,i,d,o,c){return n(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="kubernetes-k8s" tabindex="-1">Kubernetes（K8s） <a class="header-anchor" href="#kubernetes-k8s" aria-label="Permalink to “Kubernetes（K8s）”">​</a></h1><p>容器编排的事实标准，也是云原生时代的基础设施。</p><p>如果说 Docker 解决的是「怎么把应用装进容器里」，那么 Kubernetes 解决的就是「怎么让这些容器在集群里跑起来、扩得开、跑得稳」。从服务发现到负载均衡，从滚动更新到自动扩缩容，K8s 把分布式系统中最复杂的运维工作，变成了一组声明式的配置。</p><p>这篇文章系列覆盖 Kubernetes 的核心概念、存储与网络、安全与运维、Helm 包管理，以及云原生生态。无论你是要管理一个测试集群，还是为生产环境设计 K8s 架构，都能找到对应的内容。</p><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><p>Kubernetes 的知识点体系非常庞大，从核心资源对象到网络模型，从存储抽象到安全策略，每一块都需要深入理解。</p><table tabindex="0"><thead><tr><th>方向</th><th>篇数</th><th>核心目标</th></tr></thead><tbody><tr><td><a href="/devops/k8s/architecture">Kubernetes 基础</a></td><td>8 篇</td><td>架构设计、核心概念、Pod 生命周期与调度</td></tr><tr><td><a href="/devops/k8s/deployment">Kubernetes 核心资源</a></td><td>6 篇</td><td>Deployment、StatefulSet、DaemonSet、Job/CronJob</td></tr><tr><td><a href="/devops/k8s/network-model">Kubernetes 网络</a></td><td>8 篇</td><td>网络模型、DNS、Service、Ingress、CNI</td></tr><tr><td><a href="/devops/k8s/volume">Kubernetes 存储</a></td><td>5 篇</td><td>Volume、PV/PVC、StorageClass、ConfigMap/Secret</td></tr><tr><td><a href="/devops/k8s/rbac">Kubernetes 安全</a></td><td>4 篇</td><td>RBAC、Security Context、ServiceAccount、NetworkPolicy</td></tr><tr><td><a href="/devops/k8s/kubectl">Kubernetes 运维</a></td><td>10 篇</td><td>集群管理、高可用、监控、升级、Operator</td></tr><tr><td><a href="/devops/k8s/helm">Helm</a></td><td>4 篇</td><td>Chart 模板、Release 管理、Helmfile/GitOps</td></tr><tr><td><a href="/devops/k8s/cloud-native">云原生生态</a></td><td>4 篇</td><td>Service Mesh、部署策略、GitOps 工具链</td></tr></tbody></table><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to “学习路径建议”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一阶段：核心概念（1 周）</span></span>
<span class="line"><span>→ 理解 K8s 架构：Control Plane 与 Worker Node</span></span>
<span class="line"><span>→ 掌握 Pod、Deployment、Service 三大核心资源</span></span>
<span class="line"><span>→ 理解 Pod 调度机制：NodeSelector、Affinity、Taint/Toleration</span></span>
<span class="line"><span>→ 实践健康检查：Liveness Probe、Readiness Probe</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二阶段：深入原理（1-2 周）</span></span>
<span class="line"><span>→ 深入网络模型：Pod IP、Service IP、CNI 插件</span></span>
<span class="line"><span>→ 理解 PV/PVC 机制与存储抽象</span></span>
<span class="line"><span>→ 掌握 RBAC 权限管理</span></span>
<span class="line"><span>→ 理解 HPA 原理与指标体系</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三阶段：生产实践（1-2 周）</span></span>
<span class="line"><span>→ 集群高可用部署方案</span></span>
<span class="line"><span>→ etcd 备份与恢复</span></span>
<span class="line"><span>→ Prometheus + Grafana 监控体系</span></span>
<span class="line"><span>→ 滚动更新与回滚策略</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四阶段：进阶生态（持续）</span></span>
<span class="line"><span>→ Helm 模板开发与 Helmfile</span></span>
<span class="line"><span>→ Operator 开发（Kubebuilder）</span></span>
<span class="line"><span>→ Service Mesh（Istio）入门</span></span>
<span class="line"><span>→ GitOps 工作流（ArgoCD）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br></div></div><h2 id="为什么-kubernetes-是云原生的核心" tabindex="-1">为什么 Kubernetes 是云原生的核心？ <a class="header-anchor" href="#为什么-kubernetes-是云原生的核心" aria-label="Permalink to “为什么 Kubernetes 是云原生的核心？”">​</a></h2><p>云原生有四个核心特征：<strong>容器化、微服务、不可变基础设施、声明式 API</strong>。</p><p>Kubernetes 至少覆盖了其中三个。它的设计哲学是：你不告诉它「怎么做」，你只告诉它「你想要什么」。 Deployment 声明副本数是 3，它就会想方设法保证有 3 个 Pod 在跑；某个节点挂了，它会自动把 Pod 调度到其他节点上。</p><p>这种「声明式」的思维方式，是 Kubernetes 最深刻的设计，也是它区别于传统运维的根本所在。</p><h2 id="面试的核心逻辑" tabindex="-1">面试的核心逻辑 <a class="header-anchor" href="#面试的核心逻辑" aria-label="Permalink to “面试的核心逻辑”">​</a></h2><p>Kubernetes 面试通常分为三个层次：</p><p><strong>第一层：会用</strong></p><ul><li>Pod、Deployment、Service 的基本概念</li><li>kubectl 常用命令</li><li>如何暴露一个应用给集群外部访问</li></ul><p><strong>第二层：理解原理</strong></p><ul><li>Pod 调度的过程是什么？Scheduler 做了什么？</li><li>Service 的负载均衡是怎么实现的？iptables 和 IPVS 有什么区别？</li><li>网络策略（NetworkPolicy）和 CNI 插件是什么关系？</li><li>PV/PVC 的绑定过程是什么样的？</li></ul><p><strong>第三层：生产经验</strong></p><ul><li>集群是怎么做高可用的？etcd 的备份策略是什么？</li><li>遇到 OOMKilled、Pod 一直 Pending/Evicted，是怎么排查的？</li><li>如何设计一个多租户的 K8s 环境？</li><li>Pod 的资源限制设置不当会导致什么问题？</li></ul><blockquote><p>&quot;K8s 的面试官最想看到的，是你有没有「踩过坑」的经验。如果你能讲清楚一次 Pod 被驱逐的排查过程，比背一百条命令都加分。&quot;</p></blockquote>`,22)])])}const h=e(p,[["render",l]]);export{u as __pageData,h as default};
